func taskFormTitle(vm TaskFormVM) string {
	if vm.IsEdit {
		return "Edit Task"
	}
	return "New Task"
}

func taskFormSubmitLabel(vm TaskFormVM) string {
	if vm.IsEdit {
		if vm.ReadOnlyCore {
			return "Save Notes"
		}
		return "Save Changes"
	}
	return "Create Task"
}

func taskFormAction(vm TaskFormVM) string {
	if vm.IsEdit {
		return "/tasks/" + Uitoa(vm.EditingID) + "/edit"
	}
	return "/tasks"
}

func taskInputClass(hasErr bool) string {
	if hasErr {
		return "mt-2 block w-full rounded-md border border-danger bg-surface px-3 py-2 text-body text-text placeholder:text-text-muted outline-none focus:ring-2 focus:ring-danger-focus"
	}
	return "mt-2 block w-full rounded-md border border-border-input bg-surface px-3 py-2 text-body text-text placeholder:text-text-muted outline-none focus:ring-2 focus:ring-primary-focus"
}

func taskSelectedCustomerName(vm TaskFormVM) string {
	for _, customer := range vm.Customers {
		if Uitoa(customer.ID) == vm.CustomerID {
			return customer.Name
		}
	}
	return "—"
}

func taskSelectedServiceItemName(vm TaskFormVM) string {
	if vm.ServiceItemID == "" {
		return "—"
	}
	for _, item := range vm.ServiceItems {
		if Uitoa(item.ID) == vm.ServiceItemID {
			return item.Name
		}
	}
	return "—"
}

